class Solution:
    def maxJumps(self, arr, d: int) -> int:
        n = len(arr)
        memo = {}
        def dfs(i):
            if i in memo:
                return memo[i]
            best = 1
            for dx in [-1, 1]:
                for step in range(1, d + 1):
                    j = i + dx * step
                    if j < 0 or j >= n:
                        break
                    if arr[j] >= arr[i]:
                        break
                    best = max(best, 1 + dfs(j))
            memo[i] = best
            return best
        return max(dfs(i) for i in range(n))

