class Solution:
    def maxJumps(self, arr, d: int) -> int:
        n = len(arr)
        indices = sorted(range(n), key=lambda i: arr[i])
        dp = [1] * n
        for i in indices:
            for dx in [-1, 1]:
                for step in range(1, d + 1):
                    j = i + dx * step
                    if j < 0 or j >= n:
                        break
                    if arr[j] >= arr[i]:
                        break
                    dp[i] = max(dp[i], 1 + dp[j])
        return max(dp)

